// image-quality.ts — primary measurement surface for the image-carrier deblur smoke.
// PSNR is the smoke gate; MSE is exposed for debugging and downstream tooling.
// PSNR with peak=1.0 assumes both inputs share the same dynamic range — callers
// must NOT mix [0,1] linear planes with [0,255] byte planes. Pass peak=255 for byte data.

/**
 * Handles the gnosis mse workflow.
 */
export function mse(reference: Float32Array, candidate: Float32Array): number {
  if (reference.length !== candidate.length) {
    throw new RangeError(
      `mse: length mismatch (reference=${reference.length}, candidate=${candidate.length})`,
    );
  }
  const n = reference.length;
  let acc = 0;
  for (let i = 0; i < n; i++) {
    const d = reference[i] - candidate[i];
    acc += d * d;
  }
  return acc / n;
}

/**
 * Handles the gnosis psnr workflow.
 */
export function psnr(
  reference: Float32Array,
  candidate: Float32Array,
  peak: number = 1.0,
): number {
  if (reference.length !== candidate.length) {
    throw new RangeError(
      `psnr: length mismatch (reference=${reference.length}, candidate=${candidate.length})`,
    );
  }
  const err = mse(reference, candidate);
  if (err === 0) return Infinity;
  return 20 * Math.log10(peak / Math.sqrt(err));
}
